import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.BpaS1AlU.js";const m=JSON.parse('{"title":"Vision & why Omega","description":"","frontmatter":{},"headers":[],"relativePath":"guide/vision-and-why.md","filePath":"guide/vision-and-why.md"}'),s={name:"guide/vision-and-why.md"};function n(i,e,l,g,h,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="vision-why-omega" tabindex="-1">Vision &amp; why Omega <a class="header-anchor" href="#vision-why-omega" aria-label="Permalink to &quot;Vision &amp; why Omega&quot;">​</a></h1><p>Not sure Omega fits your app? Read this page first, then <strong><a href="./getting-started.html">Getting started</a></strong>.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>In growing Flutter apps, business logic often leaks into widgets: <code>setState</code>, services called from <code>build</code>, and navigation sprinkled across screens. Refactors hurt, tests need heavy UI harnesses, and new teammates lack a single map of “who decides what.”</p><h2 id="what-omega-optimizes-for" tabindex="-1">What Omega optimizes for <a class="header-anchor" href="#what-omega-optimizes-for" aria-label="Permalink to &quot;What Omega optimizes for&quot;">​</a></h2><ul><li><strong>Thin UI</strong> — screens emit <strong>intents</strong> and render <strong>expressions</strong>; they do not own domain rules.</li><li><strong>One nervous system</strong> — <strong><code>OmegaChannel</code></strong> carries events; <strong>flows</strong> and <strong>agents</strong> subscribe and collaborate predictably.</li><li><strong>Safer refactors</strong> — typed events and intents, optional <strong>contracts</strong> (debug warnings when wiring drifts).</li><li><strong>Debuggable sessions</strong> — <strong>inspector</strong> (in-app or browser + VM Service) and <strong>time-travel</strong> traces.</li><li><strong>Velocity</strong> — <strong><code>omega</code></strong> CLI scaffolds ecosystems, validates projects, and optional <strong>Omi</strong> AI helpers.</li></ul><h2 id="same-idea-as-omega-angular" tabindex="-1">Same idea as Omega Angular <a class="header-anchor" href="#same-idea-as-omega-angular" aria-label="Permalink to &quot;Same idea as Omega Angular&quot;">​</a></h2><p>If you also build on <strong>Angular</strong>, the <strong><a href="https://www.npmjs.com/package/omega-angular" target="_blank" rel="noreferrer">omega-angular</a></strong> package mirrors this model (channel, intents, flows, agents). Teams can share vocabulary across mobile and web.</p><h2 id="when-to-look-elsewhere" tabindex="-1">When to look elsewhere <a class="header-anchor" href="#when-to-look-elsewhere" aria-label="Permalink to &quot;When to look elsewhere&quot;">​</a></h2><p>Omega adds structure. Prototypes that intentionally throw away code, or apps with almost no cross-screen coordination, might not need it yet. If you adopt Omega, commit to <strong>intents + channel + flows/agents</strong> as the default path for features.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ol><li><strong><a href="./concepts.html">Core concepts</a></strong> — glossary</li><li><strong><a href="./data-flow.html">Data flow</a></strong> — end-to-end path</li><li><strong><a href="./getting-started.html">Getting started</a></strong> — install and first commands</li></ol><p>Deep reference in repo: <a href="https://github.com/yefersonSegura/omega_architecture/blob/main/doc/GUIA.md" target="_blank" rel="noreferrer">GUIA.md</a> (Spanish walkthrough with code).</p>',13)])])}const p=a(s,[["render",n]]);export{m as __pageData,p as default};
